#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define grep(b,c) for(int c=head[b];c;c=nxt[c])
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<21,stdin),p1==p2)?EOF:*p1++)
char buf[1<<23],*p1=buf,*p2=buf;
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
inline char Get(){char ch;do ch=getchar();while(ch!='A'&&ch!='C');return ch=='A';}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void chkmax(T&x,const T&y){x<y?x=y:T();}
template<typename T> inline void chkmin(T&x,const T&y){y<x?x=y:T();}

const int N=1e5+10,INF=0x3f3f3f3f; int head[N],des[N<<1],nxt[N<<1],val[N<<1],cgt,n; bool lit[N];int num;
inline void ins(const int &z,const int &x,const int &y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;val[cgt]=z;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;val[cgt]=z;
}

struct Heap
{
	std:: priority_queue<int> h,B;
	inline void push(const int &x){h.push(x);}
	inline void del(const int &x){B.push(x);}
	inline int top()
	{
		if(h.size()-B.size()==0)return -INF;
		while(!B.empty()&&h.top()==B.top()){h.pop();B.pop();}return h.top();
	}
	inline int top2()
	{
		if(h.size()-B.size()<2)return -INF;
		while(!B.empty()&&h.top()==B.top()){h.pop();B.pop();}int u=h.top();h.pop();
		while(!B.empty()&&h.top()==B.top()){h.pop();B.pop();}int v=h.top();h.push(u);
		return u+v;
	}
	inline int size(){return h.size()-B.size();}
} ToFa[N],ToMe[N],ToAl;
int stk[N],top;
namespace TreeCut
{
	int top[N],fa[N],mxs[N],siz[N],dep[N];LL dis[N];
	inline void dfs1(const int &u=1,const int &f=0)
	{		
		siz[u]=1;dep[u]=dep[fa[u]=f]+1;int mx=0;
		grep(u,i)if(des[i]!=f)
		{
			int v=des[i];dis[v]=dis[u]+val[i];dfs1(v,u);
			siz[u]+=siz[v];mx<siz[v]?mx=siz[mxs[u]=v]:0;
		}
	}
	inline void dfs2(const int &u=1,const int &fa=0,const int &tp=1)
	{
		top[u]=tp;if(mxs[u])dfs2(mxs[u],u,tp);
		grep(u,i)if(des[i]!=mxs[u]&&des[i]!=fa)dfs2(des[i],u,des[i]);
	}
	inline LL Dis(int u,int v)
	{
		LL ans=dis[u]+dis[v];
		while(top[u]!=top[v])dep[top[u]]<dep[top[v]]?v=fa[top[v]]:u=fa[top[u]];
		return ans-2*dis[dep[u]<dep[v]?u:v];
	}
}

namespace Build
{
	using TreeCut::Dis; std::vector<int> D[N];int fa[N],siz[N],lstans[N];bool vis[N];
	int Mn,Sz,Rt;inline void getRt(const int &u=1,const int &fa=0)
	{
		siz[u]=1;int mx=0;grep(u,i)if(!vis[des[i]]&&des[i]!=fa)
		{
			int v=des[i];getRt(v,u);
			siz[u]+=siz[v];chkmax(mx,siz[v]);
		}
		chkmax(mx,Sz-siz[u]); mx<Mn?Mn=mx,Rt=u:0;
	}
	int RT;inline void dfs(const int &u,const int &f=0)
	{
		ToFa[RT].push(Dis(u,fa[RT]));
		grep(u,i)if(!vis[des[i]]&&des[i]!=f)dfs(des[i],u);
	}
	inline void Solve(const int u)
	{
		vis[u]=true; if(fa[u]){dfs(RT=u);ToMe[fa[u]].push(ToFa[u].top());}
		grep(u,i)if(!vis[des[i]]) {int v=des[i];Sz=siz[v];Mn=INF;getRt(v,u);fa[Rt]=u; Solve(Rt);}
		ToMe[u].push(0);ToAl.push(lstans[u]=ToMe[u].top2());
	}
	inline void build(){Mn=INF;Sz=n;getRt(1);Solve(Rt);}
}

namespace Solve
{
	using Build :: D;
	using Build :: fa;
	using Build :: lstans;
	using TreeCut:: Dis;
	inline void del(const int &u)
	{
		--num;ToMe[u].del(0);
		int p=u;while(p)
		{
			int curans=ToMe[p].top2();
			if(curans!=lstans[p])
			{
				ToAl.del(lstans[p]);
				ToAl.push(lstans[p]=curans);
			}
			if(!fa[p])break;
			curans=ToFa[p].top();
			ToFa[p].del(Dis(u,fa[p]));
			if(ToFa[p].top()!=curans)
			{
				ToMe[fa[p]].del(curans);
				ToMe[fa[p]].push(ToFa[p].top());
			}
			p=fa[p];
		}
		
	}
	inline void ins(const int &u)
	{
		++num;ToMe[u].push(0);
		int p=u;while(p)
		{
			int curans=ToMe[p].top2();
			if(curans!=lstans[p])
			{
				ToAl.del(lstans[p]);
				ToAl.push(lstans[p]=curans);
			}
			if(!fa[p])break;
			curans=ToFa[p].top();
			ToFa[p].push(Dis(u,fa[p]));
			if(ToFa[p].top()!=curans)
			{
				ToMe[fa[p]].del(curans);
				ToMe[fa[p]].push(ToFa[p].top());
			}
			p=fa[p];
		}
		
	}
}

int main()
{
	num=n=read();rep(2,n,i)ins(read(),read(),read());
	TreeCut::dfs1(); TreeCut::dfs2(); Build::build(); 
	int Q=read(); while(Q--)
	{
		if(Get())
		{
			if(num==1) puts("0");else if(num==0)puts("They have disappeared.");
			else printf("%d\n",max(0,ToAl.top())); 
		}
		else
		{
			int x=read();lit[x]^=1;
			lit[x]?Solve::del(x):Solve::ins(x);
		}
	}
}
